// Collect all already-reviewed account_ids from the sheet
const sheetRows = $input.all();
const reviewedIds = new Set(
  sheetRows
    .map(item => item.json.account_id)
    .filter(id => id && id.trim() !== '')
);

// Pass the set as a JSON array for the next node
return [{ json: { reviewed_ids: Array.from(reviewedIds) } }];

// Get the reviewed IDs set from the previous node
const reviewedIds = new Set($node['Build Reviewed ID Set'].json.reviewed_ids || []);

// Get all accounts from the BQ node
const allAccounts = $node['Fetch Active Accounts SF + Zuora'].json;

// allAccounts may be a single item or array -- normalise
const accountsArray = Array.isArray(allAccounts) ? allAccounts : [allAccounts];

// Filter to only accounts NOT yet reviewed
const newAccounts = accountsArray.filter(acc => !reviewedIds.has(acc.account_id));

if (newAccounts.length === 0) {
  return [{ json: { no_new_accounts: true } }];
}

return newAccounts.map(acc => ({ json: acc }));

const accounts = $input.all();
const today = new Date().toISOString().split('T')[0];

return accounts.map(item => {
  const a = item.json;
  const mismatches = [];

  // A: Package / Plan
  const sfPkg = (a.sf_package || '').toLowerCase().trim();
  const zuoraPkg = (a.zuora_plan || '').toLowerCase().trim();
  if (sfPkg && zuoraPkg && sfPkg !== zuoraPkg) {
    mismatches.push('Package/Plan (SF: ' + a.sf_package + ' | Zuora: ' + a.zuora_plan + ')');
  }

  // B: MRR
  const sfMrr = parseFloat(a.sf_mrr) || 0;
  const zuoraMrr = parseFloat(a.zuora_mrr) || 0;
  if (Math.abs(sfMrr - zuoraMrr) > 0) {
    mismatches.push('MRR (SF: $' + sfMrr.toFixed(2) + ' | Zuora: $' + zuoraMrr.toFixed(2) + ')');
  }

  // C: Contract Status
  const sfStatus = (a.sf_contract_status || '').toLowerCase().trim();
  const zuoraStatus = (a.zuora_subscription_status || '').toLowerCase().trim();
  if (sfStatus && zuoraStatus && sfStatus !== zuoraStatus) {
    mismatches.push('Status (SF: ' + a.sf_contract_status + ' | Zuora: ' + a.zuora_subscription_status + ')');
  }

  // D: Billing Cycle
  const sfCycle = (a.sf_billing_cycle || '').toLowerCase().trim();
  const zuoraCycle = (a.zuora_billing_cycle || '').toLowerCase().trim();
  if (sfCycle && zuoraCycle && sfCycle !== zuoraCycle) {
    mismatches.push('Billing Cycle (SF: ' + a.sf_billing_cycle + ' | Zuora: ' + a.zuora_billing_cycle + ')');
  }

  // E: Listing Count
  const sfListings = parseFloat(a.sf_listing_count) || 0;
  const zuoraListings = parseFloat(a.zuora_listing_quantity) || 0;
  if (sfListings !== zuoraListings) {
    mismatches.push('Listings (SF: ' + sfListings + ' | Zuora: ' + zuoraListings + ')');
  }

  return {
    json: {
      account_id: a.account_id,
      account_name: a.account_name,
      account_created_at: a.account_created_at,
      reviewed_date: today,
      has_mismatch: mismatches.length > 0,
      mismatch_count: mismatches.length,
      mismatch_fields: mismatches.join(' | '),
      sf_package: a.sf_package,
      sf_mrr: a.sf_mrr,
      sf_contract_status: a.sf_contract_status,
      sf_billing_cycle: a.sf_billing_cycle,
      sf_listing_count: a.sf_listing_count,
      zuora_plan: a.zuora_plan,
      zuora_mrr: a.zuora_mrr,
      zuora_subscription_status: a.zuora_subscription_status,
      zuora_billing_cycle: a.zuora_billing_cycle,
      zuora_listing_quantity: a.zuora_listing_quantity
    }
  };
});

const mismatches = $input.all();
const today = new Date().toISOString().split('T')[0];

let lines = mismatches.map(item => {
  const a = item.json;
  return '*' + a.account_name + '* (`' + a.account_id + '`)\n  Issues: ' + a.mismatch_fields;
});

const header = ':warning: *SF vs Zuora Contract Mismatch Report -- ' + today + '*\n' +
  mismatches.length + ' account(s) with mismatches found this week.\n\n';

const body = lines.join('\n\n');
const message = header + body;

return [{ json: { slack_message: message, mismatch_count: mismatches.length } }];
